catalog_script_client.script:
function onSubmit() {
    // Clear any previous error messages
    g_form.clearMessages();

    var errors = []; // Array to collect error messages

    // 1. Check that a medicine is selected
    var medicine = g_form.getValue('medicine_name');
    if (!medicine) {
        errors.push('❌ Please select a medicine.');
    }

    // 2. Validate quantity
    var qtyField = g_form.getValue('quantity_needed');
    var validation = validateQuantity(qtyField);
    if (!validation.valid) {
        errors.push(validation.message);
    }

    // 3. Validate pickup date (not past)
    var pickupDate = g_form.getValue('preferred_pickup_date');
    if (!pickupDate) {
        errors.push('⚠️ Please select a preferred pickup date.');
    } else {
        var selectedDate = new Date(pickupDate);
        var today = new Date();
        today.setHours(0, 0, 0, 0);
        if (selectedDate < today) {
            errors.push('❌ Cannot select a past date. Please choose today or a future date.');
        }
    }

    // 4. Check availability status
    var availability = g_form.getValue('check_availability');
    if (availability === 'No') {
        errors.push('❌ The requested quantity is currently unavailable in our stock.');
    }

    // If there are errors, display them and prevent submission
    if (errors.length > 0) {
        var errorMessage = 'Please fix the following issues:\n• ' + errors.join('\n• ');
        g_form.addErrorMessage(errorMessage);
        return false;
    }

    // All validations passed
    return true;
}

// Helper function to validate quantity
function validateQuantity(value) {
    if (typeof value === 'string') value = value.trim();
    else value = String(value).trim();

    if (value === '') {
        return { valid: false, message: '⚠️ Please enter a quantity.' };
    }
    if (!/^[0-9]+$/.test(value)) {
        return { valid: false, message: '⛔ Quantity must be a number (e.g., 1, 2, 3).' };
    }
    var qty = parseInt(value, 10);
    if (qty <= 0) {
        return { valid: false, message: '⚠️ Quantity must be greater than zero.' };
    }
    if (qty > 999) {
        return { valid: false, message: '⛔ Maximum quantity allowed is 999.' };
    }
    return { valid: true, value: qty };
}
